contract;

pub fn is_char_boundary(bytes: Vec<u8>, index: u64) -> bool {
    let len = bytes.len();

    // Index equal to length is a valid boundary (end of string)
    if [[SLOT eq_check]] {
        return true;
    }

    // Index out of bounds
    if [[SLOT gt_check]] {
        return false;
    }

    let byte = [[SLOT byte_get]];

    // Check if this byte is NOT a continuation byte (10xxxxxx)
    // Continuation bytes have the pattern 10xxxxxx (0x80-0xBF)
    // A valid character boundary must not start with 10xxxxxx
    if (byte & [[SLOT mask_high]]) == [[SLOT cont_pattern]] {
        return false;
    }

    true
}
